import{_ as d,c as r,o as l,aj as o}from"./chunks/framework.CynFBi0q.js";const b=JSON.parse('{"title":"第3章 洞察市场，寻找产品机会","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_3.md","filePath":"handbook/ai-product/chapter_3.md","lastUpdated":1782008855000}'),a={name:"handbook/ai-product/chapter_3.md"};function i(e,t,h,p,n,s){return l(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="第3章-洞察市场-寻找产品机会" tabindex="-1">第3章 洞察市场，寻找产品机会 <a class="header-anchor" href="#第3章-洞察市场-寻找产品机会" aria-label="Permalink to “第3章 洞察市场，寻找产品机会”">​</a></h1><p>90%的产品失败不是因为做得不好，而是因为选错了市场。做了3年产品后我才发现，&quot;做正确的事&quot;比&quot;把事做正确&quot;重要100倍。</p><p>我是怕浪猫，这一章讲市场分析和竞品分析。不是教你列功能对比表，而是教你如何从市场中发现真正的产品机会。</p><h2 id="_3-1-市场环境解读" tabindex="-1">3.1 市场环境解读 <a class="header-anchor" href="#_3-1-市场环境解读" aria-label="Permalink to “3.1 市场环境解读”">​</a></h2><h3 id="_3-1-1-市场分析的常用工具与模型" tabindex="-1">3.1.1 市场分析的常用工具与模型 <a class="header-anchor" href="#_3-1-1-市场分析的常用工具与模型" aria-label="Permalink to “3.1.1 市场分析的常用工具与模型”">​</a></h3><p>市场分析不是拍脑袋，有一套成熟的工具和模型。产品经理最常用的五个模型：</p><table tabindex="0"><thead><tr><th>模型</th><th>用途</th><th>适用阶段</th></tr></thead><tbody><tr><td>PEST</td><td>宏观环境分析</td><td>进入新市场前</td></tr><tr><td>SWOT</td><td>内外部态势评估</td><td>战略决策时</td></tr><tr><td>波特五力</td><td>行业竞争分析</td><td>评估市场吸引力</td></tr><tr><td>价值网络</td><td>生态系统分析</td><td>平台型产品</td></tr><tr><td>用户体验地图</td><td>用户痛点分析</td><td>产品设计阶段</td></tr></tbody></table><p>这五个模型不是每次都要全用，根据场景选择最合适的。本节重点讲PEST和SWOT，它们是产品经理的基本功。</p><h3 id="_3-1-2-pest-分析-宏观环境扫描" tabindex="-1">3.1.2 PEST 分析：宏观环境扫描 <a class="header-anchor" href="#_3-1-2-pest-分析-宏观环境扫描" aria-label="Permalink to “3.1.2 PEST 分析：宏观环境扫描”">​</a></h3><p>PEST分析从四个维度扫描宏观环境：</p><p><strong>P（Political）政治环境</strong></p><ul><li>政策法规：行业准入门槛、数据安全法、反垄断法</li><li>监管趋势：监管是趋严还是趋松？</li><li>政府态度：鼓励还是限制？</li></ul><p>实例：2021年教育&quot;双减&quot;政策，直接改变了在线教育行业的市场格局。如果你在2020年做教育产品，没有做政策维度的PEST分析，2021年就会措手不及。</p><p><strong>E（Economic）经济环境</strong></p><ul><li>经济周期：上行期还是下行期？</li><li>消费能力：目标用户的可支配收入如何？</li><li>融资环境：资本市场是宽松还是紧缩？</li></ul><p>实例：2022年经济下行，消费降级趋势明显。拼多多逆势增长，而高端消费平台承压。如果你的产品定位高端消费，不做经济维度分析就可能逆势而为。</p><p><strong>S（Social）社会环境</strong></p><ul><li>人口结构：老龄化、少子化、城市化</li><li>消费习惯：线上消费占比、消费观念变化</li><li>文化趋势：国潮、健康、个性化</li></ul><p>实例：老龄化趋势催生了银发经济——老年社交、健康管理、适老化改造成为新的产品方向。</p><p><strong>T（Technological）技术环境</strong></p><ul><li>核心技术突破：大模型、5G、AR/VR</li><li>技术成熟度：技术是否到达商业化拐点？</li><li>技术替代风险：现有技术是否可能被颠覆？</li></ul><p>实例：2023年大模型技术突破，直接催生了AI写作、AI绘画、AI编程等新产品品类。不做技术维度分析，就会错过技术红利期。</p><blockquote><p>PEST分析不是&quot;填表游戏&quot;，而是&quot;预判未来&quot;。你不需要预测每一个变化，但你需要识别最重要的趋势，并在产品规划中提前布局。</p></blockquote><p><strong>PEST分析模板</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>关键因素</th><th>对产品的影响</th><th>应对策略</th></tr></thead><tbody><tr><td>政治</td><td>数据安全法</td><td>数据合规成本增加</td><td>提前建设合规体系</td></tr><tr><td>经济</td><td>消费降级</td><td>高端产品承压</td><td>推出平价产品线</td></tr><tr><td>社会</td><td>老龄化</td><td>银发市场机会</td><td>适老化产品设计</td></tr><tr><td>技术</td><td>大模型</td><td>AI产品爆发</td><td>提前储备AI能力</td></tr></tbody></table><h3 id="_3-1-3-swot-分析-内外部态势评估" tabindex="-1">3.1.3 SWOT 分析：内外部态势评估 <a class="header-anchor" href="#_3-1-3-swot-分析-内外部态势评估" aria-label="Permalink to “3.1.3 SWOT 分析：内外部态势评估”">​</a></h3><p>SWOT分析从四个维度评估产品/公司的态势：</p><p><strong>S（Strengths）优势：我们擅长什么？</strong></p><ul><li>核心技术能力</li><li>用户规模和活跃度</li><li>品牌认知度</li><li>独特资源（数据、渠道、牌照）</li></ul><p><strong>W（Weaknesses）劣势：我们不擅长什么？</strong></p><ul><li>技术短板</li><li>用户结构不合理</li><li>品牌影响力弱</li><li>资源不足</li></ul><p><strong>O（Opportunities）机会：外部有什么利好？</strong></p><ul><li>新技术带来的产品机会</li><li>政策鼓励的方向</li><li>市场空白</li><li>用户需求升级</li></ul><p><strong>T（Threats）威胁：外部有什么风险？</strong></p><ul><li>竞品进入</li><li>政策收紧</li><li>技术替代</li><li>用户流失</li></ul><p>SWOT分析的关键不是&quot;列出来&quot;，而是&quot;交叉分析&quot;：</p><table tabindex="0"><thead><tr><th>交叉</th><th>策略</th><th>说明</th></tr></thead><tbody><tr><td>S+O</td><td>增长策略</td><td>用优势抓住机会</td></tr><tr><td>W+O</td><td>改进策略</td><td>克服劣势抓住机会</td></tr><tr><td>S+T</td><td>防御策略</td><td>用优势应对威胁</td></tr><tr><td>W+T</td><td>生存策略</td><td>避免劣势暴露在威胁下</td></tr></tbody></table><p><strong>SWOT分析实例：某中型社交产品</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>S</td><td>社区氛围好、用户忠诚度高、内容质量优</td></tr><tr><td>W</td><td>用户规模小、变现能力弱、技术团队薄</td></tr><tr><td>O</td><td>AI推荐技术成熟、垂类社交受资本关注</td></tr><tr><td>T</td><td>头部平台推出类似功能、用户时间被短视频抢占</td></tr></tbody></table><p>交叉分析：</p><ul><li>S+O：利用优质内容+AI推荐，提升内容分发效率，吸引更多用户</li><li>W+O：借助外部AI能力，弥补技术短板</li><li>S+T：强化社区氛围和内容质量，和头部平台形成差异化</li><li>W+T：避免和头部平台正面竞争，聚焦垂类市场</li></ul><h3 id="_3-1-4-垂类市场现状解读-各行业赛道概览" tabindex="-1">3.1.4 垂类市场现状解读：各行业赛道概览 <a class="header-anchor" href="#_3-1-4-垂类市场现状解读-各行业赛道概览" aria-label="Permalink to “3.1.4 垂类市场现状解读：各行业赛道概览”">​</a></h3><p>产品经理需要了解主要赛道的市场格局，才能判断产品机会在哪里。</p><p><strong>主流赛道一览</strong></p><table tabindex="0"><thead><tr><th>赛道</th><th>市场规模</th><th>增长率</th><th>竞争格局</th><th>机会方向</th></tr></thead><tbody><tr><td>社交</td><td>千亿级</td><td>低增长</td><td>头部垄断</td><td>垂类社交、AI社交</td></tr><tr><td>电商</td><td>万亿级</td><td>中增长</td><td>多强并立</td><td>直播电商、跨境</td></tr><tr><td>短视频</td><td>千亿级</td><td>低增长</td><td>双寡头</td><td>垂类内容、商业化工具</td></tr><tr><td>教育</td><td>千亿级</td><td>负增长</td><td>严监管</td><td>职业教育、AI教育</td></tr><tr><td>医疗</td><td>千亿级</td><td>高增长</td><td>分散</td><td>AI问诊、数字疗法</td></tr><tr><td>金融</td><td>万亿级</td><td>中增长</td><td>强监管</td><td>智能投顾、保险科技</td></tr><tr><td>本地生活</td><td>千亿级</td><td>中增长</td><td>双寡头</td><td>细分场景、供给侧</td></tr><tr><td>SaaS</td><td>百亿级</td><td>高增长</td><td>分散</td><td>垂类SaaS、AI+SaaS</td></tr></tbody></table><blockquote><p>选赛道比选功能重要。在增长市场里，产品方向对了，犯错也有容错空间。在萎缩市场里，产品做得再好也是逆水行舟。</p></blockquote><h2 id="_3-2-竞品分析实战" tabindex="-1">3.2 竞品分析实战 <a class="header-anchor" href="#_3-2-竞品分析实战" aria-label="Permalink to “3.2 竞品分析实战”">​</a></h2><h3 id="_3-2-1-竞品分析的思路与框架" tabindex="-1">3.2.1 竞品分析的思路与框架 <a class="header-anchor" href="#_3-2-1-竞品分析的思路与框架" aria-label="Permalink to “3.2.1 竞品分析的思路与框架”">​</a></h3><p>竞品分析不是&quot;抄作业&quot;，而是&quot;理解竞争格局，找到差异化空间&quot;。</p><p>很多产品经理做竞品分析就是下载几个竞品App，截图对比功能，写一份报告交差。这种分析几乎没有任何价值，因为：</p><ol><li>功能对比只能看到&quot;表象&quot;，看不到&quot;原因&quot;</li><li>竞品的功能不一定适合你的产品</li><li>竞品的&quot;功能&quot;可能是它的&quot;战略选择&quot;而非&quot;最优解&quot;</li></ol><p>真正有价值的竞品分析，要从四个层面看：</p><p><strong>第一层：产品层</strong>——竞品做了什么功能？ <strong>第二层：策略层</strong>——竞品为什么做这个功能？ <strong>第三层：数据层</strong>——竞品这个功能效果如何？ <strong>第四层：趋势层</strong>——竞品下一步可能做什么？</p><blockquote><p>竞品分析的价值不在于&quot;抄&quot;，而在于&quot;理解&quot;。理解竞品的战略意图，才能找到差异化空间。</p></blockquote><h3 id="_3-2-2-竞品选择与分层方法" tabindex="-1">3.2.2 竞品选择与分层方法 <a class="header-anchor" href="#_3-2-2-竞品选择与分层方法" aria-label="Permalink to “3.2.2 竞品选择与分层方法”">​</a></h3><p>不是所有竞品都值得深入分析。竞品选择有三个原则：</p><p><strong>原则一：分层选竞品</strong></p><table tabindex="0"><thead><tr><th>层级</th><th>类型</th><th>数量</th><th>分析深度</th></tr></thead><tbody><tr><td>直接竞品</td><td>解决相同用户相同问题</td><td>2-3个</td><td>深度分析</td></tr><tr><td>间接竞品</td><td>解决相同用户不同问题</td><td>2-3个</td><td>中度分析</td></tr><tr><td>潜在竞品</td><td>可能进入你赛道的产品</td><td>1-2个</td><td>浅度分析</td></tr></tbody></table><p><strong>原则二：选&quot;最好的&quot;而不是&quot;最像的&quot;</strong></p><p>分析微信支付时，不要只看支付宝，还要看银联、数字人民币。分析抖音时，不要只看快手，还要看B站和小红书。最好的竞品可能不在你的赛道，但在争夺同样的用户时间。</p><p><strong>原则三：动态更新竞品列表</strong></p><p>竞品不是一成不变的。去年还在分析OFO，今年就没有了。每季度更新一次竞品列表，保持对市场的敏感度。</p><h3 id="_3-2-3-竞品功能对比与差异化提炼" tabindex="-1">3.2.3 竞品功能对比与差异化提炼 <a class="header-anchor" href="#_3-2-3-竞品功能对比与差异化提炼" aria-label="Permalink to “3.2.3 竞品功能对比与差异化提炼”">​</a></h3><p>功能对比是竞品分析的基础，但要做对不容易。</p><p><strong>功能对比三步法</strong></p><p><strong>第一步：功能清单提取</strong></p><p>不是简单列&quot;有/没有&quot;，而是按用户场景梳理功能：</p><table tabindex="0"><thead><tr><th>用户场景</th><th>竞品A</th><th>竞品B</th><th>我们</th></tr></thead><tbody><tr><td>首次注册</td><td>手机号+微信</td><td>手机号+微信+Apple</td><td>手机号</td></tr><tr><td>内容浏览</td><td>算法推荐</td><td>关注流+推荐</td><td>编辑推荐</td></tr><tr><td>内容发布</td><td>图文+视频+直播</td><td>图文+视频</td><td>图文</td></tr><tr><td>社交互动</td><td>点赞+评论+分享</td><td>点赞+评论+弹幕</td><td>点赞+评论</td></tr></tbody></table><p><strong>第二步：功能深度分析</strong></p><p>不只是看功能有没有，还要看做得怎么样：</p><ul><li>功能完整度：覆盖了多少使用场景？</li><li>体验流畅度：操作路径有多长？</li><li>个性化程度：能否根据用户偏好调整？</li><li>性能表现：速度、稳定性如何？</li></ul><p><strong>第三步：差异化提炼</strong></p><p>功能对比的最终目的，是找到差异化空间。差异化有三个方向：</p><ol><li><strong>做竞品没做的</strong>：满足用户需求但竞品忽视的场景</li><li><strong>做竞品做得差的</strong>：竞品有但体验不好的功能</li><li><strong>做竞品做不了的</strong>：利用自身独特资源的差异化能力</li></ol><p><strong>差异化分析模板</strong></p><table tabindex="0"><thead><tr><th>差异化方向</th><th>具体功能</th><th>竞品现状</th><th>我们的方案</th><th>预期效果</th></tr></thead><tbody><tr><td>竞品没做</td><td>XXX场景</td><td>无覆盖</td><td>创新方案</td><td>先发优势</td></tr><tr><td>竞品做得差</td><td>XXX功能</td><td>体验差</td><td>优化方案</td><td>体验差异化</td></tr><tr><td>竞品做不了</td><td>XXX能力</td><td>资源限制</td><td>资源优势</td><td>壁垒差异化</td></tr></tbody></table><h3 id="_3-2-4-产出一份竞品分析报告" tabindex="-1">3.2.4 产出一份竞品分析报告 <a class="header-anchor" href="#_3-2-4-产出一份竞品分析报告" aria-label="Permalink to “3.2.4 产出一份竞品分析报告”">​</a></h3><p>竞品分析报告不是&quot;写给老板看的PPT&quot;，而是&quot;给自己做决策的依据&quot;。</p><p>一份好的竞品分析报告包含以下部分：</p><p><strong>1. 市场概览</strong>（1页）</p><ul><li>市场规模和增长率</li><li>竞争格局图</li><li>主要玩家及其市场份额</li></ul><p><strong>2. 竞品概览</strong>（1-2页）</p><ul><li>各竞品的定位和核心策略</li><li>用户规模和增长趋势</li><li>商业模式对比</li></ul><p><strong>3. 功能对比</strong>（2-3页）</p><ul><li>核心功能对比表</li><li>关键功能的深度分析</li><li>用户体验差异</li></ul><p><strong>4. 策略分析</strong>（1-2页）</p><ul><li>各竞品的战略意图推断</li><li>竞品的优势和劣势</li><li>竞品的可能动向</li></ul><p><strong>5. 差异化建议</strong>（1页）</p><ul><li>我们的差异化方向</li><li>具体功能建议</li><li>预期效果和风险</li></ul><p><strong>6. 行动计划</strong>（0.5页）</p><ul><li>短期：可以立刻做的</li><li>中期：需要规划的</li><li>长期：需要持续关注的</li></ul><blockquote><p>竞品分析报告的价值，不在于你写了多少页，而在于你发现了多少别人没看到的东西。一份3页但有洞察的报告，远胜于一份30页只罗列功能的报告。</p></blockquote><p><strong>竞品分析报告自检清单</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>是否完成</th></tr></thead><tbody><tr><td>竞品选择是否合理（直接+间接+潜在）</td><td></td></tr><tr><td>功能对比是否基于用户场景</td><td></td></tr><tr><td>是否分析了功能背后的策略意图</td><td></td></tr><tr><td>是否提炼了差异化方向</td><td></td></tr><tr><td>是否给出了可执行的行动建议</td><td></td></tr><tr><td>报告是否简洁，重点突出</td><td></td></tr></tbody></table><hr><p>本章小结：市场分析和竞品分析是产品经理的&quot;望远镜&quot;和&quot;显微镜&quot;。PEST和SWOT帮你看清宏观趋势，竞品分析帮你看清竞争格局。两者的结合，让你能从市场中找到真正的产品机会。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>PEST分析</td><td>扫描宏观环境，预判趋势</td></tr><tr><td>SWOT分析</td><td>评估内外部态势，制定策略</td></tr><tr><td>竞品分析四层法</td><td>产品→策略→数据→趋势</td></tr><tr><td>差异化三方向</td><td>没做的/做得差的/做不了的</td></tr><tr><td>竞品报告</td><td>重洞察轻罗列，重决策轻展示</td></tr></tbody></table><p>觉得有用？收藏起来，下次做竞品分析时直接照抄模板。</p><p>你做竞品分析时踩过什么坑？评论区说说。</p><p>关注怕浪猫，下期我们讲&quot;收集需求，明确产品定位&quot;——用户调研怎么做、需求怎么管理、产品怎么定位，一套方法论讲透。</p><p>系列进度 3/16</p><p><strong>下章预告：</strong> 第4章，怕浪猫教你需求管理。很多产品经理被需求淹没了——运营提需求、老板提需求、用户提需求，怎么判断哪些该做哪些不该做？KANO模型、MoSCoW方法、RICE评分，这些工具我帮你一次性讲清楚。</p>',102)])])}const g=d(a,[["render",i]]);export{b as __pageData,g as default};
